-- row_id=21, COMCODE=1111255, 赛力斯汽车
UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"模块化方案：依托与华为合作的HUAWEI ADS乾崑智驾系统，迭代至3.0版本采用端到端架构，支持车位到车位全场景智驾，4.0版本2025年三季度落地，同步自研中低端车型辅助驾驶算法形成差异化矩阵\\n前沿演进：采用“AI+后处理算法”路线，搭配MOE多专家模型与多传感器融合感知方案，GOD2.0+RCR2.0网络实现无高精地图环境感知，电子电气架构支持大模型应用与端到端演进\\n多路线并存：高阶智驾核心算法由华为提供，赛力斯负责整车适配与场景优化，双方联合迭代，同时布局自主算法路线满足不同层级产品需求","raw_value":"模块化方案：依托与华为合作的HUAWEI ADS乾崑智驾系统，迭代至3.0版本采用端到端架构，支持车位到车位全场景智驾，4.0版本2025年三季度落地，同步自研中低端车型辅助驾驶算法形成差异化矩阵\\n前沿演进：采用“AI+后处理算法”路线，搭配MOE多专家模型与多传感器融合感知方案，GOD2.0+RCR2.0网络实现无高精地图环境感知，电子电气架构支持大模型应用与端到端演进\\n多路线并存：高阶智驾核心算法由华为提供，赛力斯负责整车适配与场景优化，双方联合迭代，同时布局自主算法路线满足不同层级产品需求","unit":null,"data_source":"Agent final_report","source_link":"https://htfic.htzq.com.cn/ht/report/vsat/2025/05/30/202505300002GC005N.pdf","quote_text":"【算法路线证据1】本文聚焦赛力斯与华为合作的智驾系统HUAWEI ADS的迭代发展。HUAWEI ADS已更新至3.0版本，1.0版本于2021年发布，基于BEV网络和传统规控算法，依赖高精地图，开城进度慢，2022年仅落地深圳、上海。2.0版本2023年发布，运用GOD和RCR网络，摆脱对高精地图依赖，2024年2月完成全国99％公开道路覆盖。3.0版本2024年发布，采用端到端架构，实现感知到决策一体化，显著提升城市智驾表现，能完成复杂场景“车位到车位”智驾。此外，4.0版本将于2025年三季度上车问界M9、M8 ，并规划推出高速L3级自动驾驶商用及城区L3级自动驾驶试点。\\n【算法路线证据2】在技术路径选择上，段文平明确指出：问界坚持创新的“AI+后处理算法”路线与多传感器融合感知方案。其中，“AI+后处理算法”路线通过优化传感器数据输入、调用MOE多专家模型，兼顾安全上下限与体验稳定性；多传感器融合路线则通过不同传感器的能力互补，确保全天候、全场景及恶劣天气下的安全感知精度，显著提升了复杂环境下的安全冗余。\\n【算法路线证据3】电子电气架构：从“分布式区域控制”升级为“中央车控+区域控制”，支持大模型应用与端到端演进，为高阶智驾预留算力，可埋L4级自动驾驶硬件，实现了敏锐感知、聪明决策、高效执行。\\n【算法路线证据4】高阶智驾算法核心技术由华为提供，包含感知算法、决策规划算法、控制算法及配套大模型底座，赛力斯负责整车适配、特定场景优化、用户定制化功能调试，双方联合推进算法实车迭代。同步组建自研智能驾驶研发团队，投入研发面向中低端车型的独立辅助驾驶算法路线，与华为合作的高阶智驾路线形成产品矩阵差异化布局，目前自研算法尚未实现大规模量产落地。\\n【算力基础设施证据1】魔方技术平台2.0的电子电气架构完成了从“分布式区域控制”向“中央车控+区域控制”的进化。这就好比为车辆安装了一个更强大的“中央大脑”，能够实现跨域协同与高效决策。这种架构支持大模型应用以及端到端演进，实现了敏锐感知、聪明决策与高效执行。这正是AI定义汽车与传统智能汽车的根本差异。更值得关注的是，赛力斯正将技术优势转化为可持续的产业生态优势。通过构建“汽车产业大脑”，实现与核心供应商的直通协同、全链路数据贯通以及算力底座的支持。这套体系打破了传统链式合作模式，形成了以数据和AI驱动的融合创新网络，为未来的快速迭代构筑了坚实护城河。\\n【算力基础设施证据2】旗下问界M7 Max、问界M9 Max等搭载高阶智驾功能的量产车型，配套华为MDC 810智能驾驶计算平台，INT8算力为400TOPS，可支持城区NCA、高速NCA等全场景高阶智驾功能，统计口径为2024年在售车型。联合华为搭建智能驾驶专用训练算力集群，总算力规模超过1000PFLOPS，用于智能驾驶算法训练、仿真测试、数据标注处理等场景，支撑高阶智驾功能迭代，该集群2023年建成。端侧算力随量产车型搭载落地，云端智算集群分别布局在重庆（赛力斯总部基地）、深圳（华为智能汽车解决方案研发基地）两地，实现两地算力协同调度。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_1111255","collection_result_row_id":"CRR_ALGO_COMPUTE_1111255_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：高阶智驾车型搭载华为MDC 810计算平台，算力达400TOPS，魔方技术平台2.0采用中央车控+区域控制架构，实现算力集中调度与大模型原生支持\\n自研芯片：暂无公开自研车端智驾芯片量产规划，联合华为搭建超1000PFLOPS智算集群，布局重庆、深圳两地协同支撑算法训练与产业协同","raw_value":"车端芯片：高阶智驾车型搭载华为MDC 810计算平台，算力达400TOPS，魔方技术平台2.0采用中央车控+区域控制架构，实现算力集中调度与大模型原生支持\\n自研芯片：暂无公开自研车端智驾芯片量产规划，联合华为搭建超1000PFLOPS智算集群，布局重庆、深圳两地协同支撑算法训练与产业协同","unit":null,"data_source":"Agent final_report","source_link":"https://htfic.htzq.com.cn/ht/report/vsat/2025/05/30/202505300002GC005N.pdf","quote_text":"【算法路线证据1】本文聚焦赛力斯与华为合作的智驾系统HUAWEI ADS的迭代发展。HUAWEI ADS已更新至3.0版本，1.0版本于2021年发布，基于BEV网络和传统规控算法，依赖高精地图，开城进度慢，2022年仅落地深圳、上海。2.0版本2023年发布，运用GOD和RCR网络，摆脱对高精地图依赖，2024年2月完成全国99％公开道路覆盖。3.0版本2024年发布，采用端到端架构，实现感知到决策一体化，显著提升城市智驾表现，能完成复杂场景“车位到车位”智驾。此外，4.0版本将于2025年三季度上车问界M9、M8 ，并规划推出高速L3级自动驾驶商用及城区L3级自动驾驶试点。\\n【算法路线证据2】在技术路径选择上，段文平明确指出：问界坚持创新的“AI+后处理算法”路线与多传感器融合感知方案。其中，“AI+后处理算法”路线通过优化传感器数据输入、调用MOE多专家模型，兼顾安全上下限与体验稳定性；多传感器融合路线则通过不同传感器的能力互补，确保全天候、全场景及恶劣天气下的安全感知精度，显著提升了复杂环境下的安全冗余。\\n【算法路线证据3】电子电气架构：从“分布式区域控制”升级为“中央车控+区域控制”，支持大模型应用与端到端演进，为高阶智驾预留算力，可埋L4级自动驾驶硬件，实现了敏锐感知、聪明决策、高效执行。\\n【算法路线证据4】高阶智驾算法核心技术由华为提供，包含感知算法、决策规划算法、控制算法及配套大模型底座，赛力斯负责整车适配、特定场景优化、用户定制化功能调试，双方联合推进算法实车迭代。同步组建自研智能驾驶研发团队，投入研发面向中低端车型的独立辅助驾驶算法路线，与华为合作的高阶智驾路线形成产品矩阵差异化布局，目前自研算法尚未实现大规模量产落地。\\n【算力基础设施证据1】魔方技术平台2.0的电子电气架构完成了从“分布式区域控制”向“中央车控+区域控制”的进化。这就好比为车辆安装了一个更强大的“中央大脑”，能够实现跨域协同与高效决策。这种架构支持大模型应用以及端到端演进，实现了敏锐感知、聪明决策与高效执行。这正是AI定义汽车与传统智能汽车的根本差异。更值得关注的是，赛力斯正将技术优势转化为可持续的产业生态优势。通过构建“汽车产业大脑”，实现与核心供应商的直通协同、全链路数据贯通以及算力底座的支持。这套体系打破了传统链式合作模式，形成了以数据和AI驱动的融合创新网络，为未来的快速迭代构筑了坚实护城河。\\n【算力基础设施证据2】旗下问界M7 Max、问界M9 Max等搭载高阶智驾功能的量产车型，配套华为MDC 810智能驾驶计算平台，INT8算力为400TOPS，可支持城区NCA、高速NCA等全场景高阶智驾功能，统计口径为2024年在售车型。联合华为搭建智能驾驶专用训练算力集群，总算力规模超过1000PFLOPS，用于智能驾驶算法训练、仿真测试、数据标注处理等场景，支撑高阶智驾功能迭代，该集群2023年建成。端侧算力随量产车型搭载落地，云端智算集群分别布局在重庆（赛力斯总部基地）、深圳（华为智能汽车解决方案研发基地）两地，实现两地算力协同调度。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_1111255","collection_result_row_id":"CRR_ALGO_COMPUTE_1111255_COMPUTEPOWERDESC","collected_at":"2026-03-13 15:13:04"}}'),
