-- row_id=22, COMCODE=351942, 吉利汽车
UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"自研+供应商双线布局：高阶智驾自研BEV Transformer、决策规控、端到端大模型，中低阶采用毫末智行、博世、Mobileye方案\\n前沿演进：搭载WAM世界行为模型，运用1000亿级云端多模态大模型+世界模型，升级生成式范式落地多模态Diffusion技术\\n多路线并存：联合千里智驾研发G-ASD方案，采用Smart AI Agent架构，融入阶跃星辰通用大模型及国宾级司机驾驶数据","raw_value":"自研+供应商双线布局：高阶智驾自研BEV Transformer、决策规控、端到端大模型，中低阶采用毫末智行、博世、Mobileye方案\\n前沿演进：搭载WAM世界行为模型，运用1000亿级云端多模态大模型+世界模型，升级生成式范式落地多模态Diffusion技术\\n多路线并存：联合千里智驾研发G-ASD方案，采用Smart AI Agent架构，融入阶跃星辰通用大模型及国宾级司机驾驶数据","unit":null,"data_source":"Agent final_report","source_link":"http://www.xinhuanet.com/auto/20260114/231a9da94ef54d348c15bb41f21fedcc/c.html","quote_text":"【算法路线证据1】当地时间1月5日，吉利汽车集团在美国拉斯维加斯宣布基于其首发的WAM世界行为模型，吉利全域AI技术体系顺利进化到了2.0时代，实现了AI技术在整车各域的跨域融合，让汽车智能首次拥有了持续进化的“世界观”和“判断力”。同时，吉利还发布了千里浩瀚辅助驾驶系统的英文品牌及软件版本名称——千里浩瀚G-ASD，代表着吉利与千里智驾联合研发的高含模量智能辅助驾驶解决方案，旨在为吉利体系下的用户提供同等级下最优质的体验。为了让智驾域、座舱域、底盘域等各个域之间充分实现跨域融合，吉利今年发布了具备自我反思与进化能力的世界行为模型——WAM（World Action Model），构建统一的“整车大脑”。WAM采用了分层设计，上层利用MLLM（多模态模型）进行宏观任务的规划，下层集成动作专家（Action Expert）和世界模型（World Model）进行精细的推演和决策，并引入人类在环（Human-in-the-loop）的价值函数体系（Value Function），实现了从“理解-规划”到“预演-判断-修正”的完整智能闭环，让汽车智能首次拥有持续进化的“世界观”和“判断力”。千里浩瀚G-ASD采用行业领先的SmartAIAgent架构，完整应用了WAM世界行为模型,是全球范围内“含模量”超高、紧随技术前沿的辅助驾驶系统之一。在阶跃星辰通用AI大模型的加持下，云端多模态大模型+世界模型参数达1000亿级别，显著提升环境感知和推理能力。同时，千里浩瀚G-ASD还将模型范式全面升级为生成式范式，落地多模态Diffusion技术，并融入国宾级司机的驾驶行为数据，全面提升辅助驾驶的拟人性、安全性、舒适性和通行效率。\\n【算法路线证据2】采用自研+核心供应商协同的双线布局，高阶智驾核心算法以自主研发为主，中低阶智驾场景搭载第三方供应商成熟落地方案；自研技术覆盖BEV Transformer感知架构、决策规控算法、端到端智驾大模型三大核心模块，相关技术优先搭载于银河、领克品牌的高端配置车型；中低阶智驾场景合作供应商包括毫末智行、博世、Mobileye，采用供应商提供的成熟感知、规控打包方案，适配10-20万价位走量车型，降低智驾配置落地成本；自研BEV Transformer感知架构支持环视相机、激光雷达、毫米波雷达多模态融合感知，最远感知距离250米，可覆盖城区NOA、高速NOA、自动泊车等全场景高阶智驾功能，2024年已量产搭载于吉利银河L7 MAX等车型。\\n【算力基础设施证据1】图表33：各主流车企域控芯片自研情况<br>","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_351942","collection_result_row_id":"CRR_ALGO_COMPUTE_351942_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：覆盖英伟达Orin X（单颗254TOPS）、Thor（275-1000TOPS）、地平线征程5（单颗128TOPS），极氪9X双Thor芯片算力达1400TOPS\\n自研芯片：芯擎科技7nm龙鹰智驾AD1000单颗256TOPS，4颗组合最高1024TOPS，已量产适配L2-L4级智驾场景","raw_value":"车端芯片：覆盖英伟达Orin X（单颗254TOPS）、Thor（275-1000TOPS）、地平线征程5（单颗128TOPS），极氪9X双Thor芯片算力达1400TOPS\\n自研芯片：芯擎科技7nm龙鹰智驾AD1000单颗256TOPS，4颗组合最高1024TOPS，已量产适配L2-L4级智驾场景","unit":null,"data_source":"Agent final_report","source_link":"http://www.xinhuanet.com/auto/20260114/231a9da94ef54d348c15bb41f21fedcc/c.html","quote_text":"【算法路线证据1】当地时间1月5日，吉利汽车集团在美国拉斯维加斯宣布基于其首发的WAM世界行为模型，吉利全域AI技术体系顺利进化到了2.0时代，实现了AI技术在整车各域的跨域融合，让汽车智能首次拥有了持续进化的“世界观”和“判断力”。同时，吉利还发布了千里浩瀚辅助驾驶系统的英文品牌及软件版本名称——千里浩瀚G-ASD，代表着吉利与千里智驾联合研发的高含模量智能辅助驾驶解决方案，旨在为吉利体系下的用户提供同等级下最优质的体验。为了让智驾域、座舱域、底盘域等各个域之间充分实现跨域融合，吉利今年发布了具备自我反思与进化能力的世界行为模型——WAM（World Action Model），构建统一的“整车大脑”。WAM采用了分层设计，上层利用MLLM（多模态模型）进行宏观任务的规划，下层集成动作专家（Action Expert）和世界模型（World Model）进行精细的推演和决策，并引入人类在环（Human-in-the-loop）的价值函数体系（Value Function），实现了从“理解-规划”到“预演-判断-修正”的完整智能闭环，让汽车智能首次拥有持续进化的“世界观”和“判断力”。千里浩瀚G-ASD采用行业领先的SmartAIAgent架构，完整应用了WAM世界行为模型,是全球范围内“含模量”超高、紧随技术前沿的辅助驾驶系统之一。在阶跃星辰通用AI大模型的加持下，云端多模态大模型+世界模型参数达1000亿级别，显著提升环境感知和推理能力。同时，千里浩瀚G-ASD还将模型范式全面升级为生成式范式，落地多模态Diffusion技术，并融入国宾级司机的驾驶行为数据，全面提升辅助驾驶的拟人性、安全性、舒适性和通行效率。\\n【算法路线证据2】采用自研+核心供应商协同的双线布局，高阶智驾核心算法以自主研发为主，中低阶智驾场景搭载第三方供应商成熟落地方案；自研技术覆盖BEV Transformer感知架构、决策规控算法、端到端智驾大模型三大核心模块，相关技术优先搭载于银河、领克品牌的高端配置车型；中低阶智驾场景合作供应商包括毫末智行、博世、Mobileye，采用供应商提供的成熟感知、规控打包方案，适配10-20万价位走量车型，降低智驾配置落地成本；自研BEV Transformer感知架构支持环视相机、激光雷达、毫米波雷达多模态融合感知，最远感知距离250米，可覆盖城区NOA、高速NOA、自动泊车等全场景高阶智驾功能，2024年已量产搭载于吉利银河L7 MAX等车型。\\n【算力基础设施证据1】图表33：各主流车企域控芯片自研情况<br>","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_351942","collection_result_row_id":"CRR_ALGO_COMPUTE_351942_COMPUTEPOWERDESC","collected_at":"2026-03-13 15:13:04"}}'),
