UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"模块化方案：采用渐进式端到端研发路线，升级NADArch2.0架构，搭载自研蔚来世界模型NWM，搭配NSim生成式仿真模型形成闭环测试能力，已量产端到端AEB等功能，技术范式为「蔚来世界模型」+「闭环强化学习」；\\n前沿演进：NWM为多元自回归生成式具身驾驶模型，具备空间理解、时间理解、海量数据无监督学习三大核心能力，可100毫秒推演216种行驶轨迹并更新迭代，前期已落地基于Transformer的BEV多模态感知方案；\\n多路线并存：秉持「人车共驾」理念，优先落地主动安全相关功能，同步推进BEV感知优化与端到端大模型落地，降低高精地图依赖，提升城市场景覆盖率。","raw_value":"模块化方案：采用渐进式端到端研发路线，升级NADArch2.0架构，搭载自研蔚来世界模型NWM，搭配NSim生成式仿真模型形成闭环测试能力，已量产端到端AEB等功能，技术范式为「蔚来世界模型」+「闭环强化学习」；\\n前沿演进：NWM为多元自回归生成式具身驾驶模型，具备空间理解、时间理解、海量数据无监督学习三大核心能力，可100毫秒推演216种行驶轨迹并更新迭代，前期已落地基于Transformer的BEV多模态感知方案；\\n多路线并存：秉持「人车共驾」理念，优先落地主动安全相关功能，同步推进BEV感知优化与端到端大模型落地，降低高精地图依赖，提升城市场景覆盖率。","unit":null,"data_source":"Agent final_report","source_link":"https://www.thepaper.cn/newsDetail_forward_28053830","quote_text":"【算法路线证据】对于蔚来来说，在端到端大模型方面采用的是渐进式的路线。在他们看来做端到端大模型的前提是要让智驾各功能模块都已形成模型化，具备足够的性能和工程效率。简单说就像是先有每块功能化的拼图，然后组装为整张端到端的完整拼图，不然就像蔚来智能驾驶研发副总裁任少卿认为的那样“否则端到端就是个毒药。”这两天，蔚来推送了Banyan 2.6.5版本，其中包括端到端的AEB功能，可以让AEB避险能力显著增强。随着今年6月蔚来内部智驾团队架构完成调整后，蔚来也成为了率先量产端到端智驾功能的车企。\\n【算力基础设施证据】算力竞赛升级（1000＋TOPS）：芯片单颗算力普遍瞄准400 TOPS以上，蔚来神机NX9031和小鹏图灵更是突破700-1000＋TOPS，满足更高阶自动驾驶（L3＋）的算力需求。先进制程成为主流（7nm／5nm）：主要芯片均采用7nm（华为、小鹏、芯擎）或更先进的5nm（蔚来）制程工艺，紧跟技术前沿。首搭车型定位清晰：芯片将率先搭载在各自品牌的旗舰或高端车型上（如蔚来ET9、小鹏G7 Ultra），覆盖22-80万价格区间。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_5209493","collection_result_row_id":"CRR_ALGO_COMPUTE_5209493_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：NT2.0平台车型搭载4颗英伟达Orin X芯片，智驾总算力1016TOPS；ET9搭载双自研神玑NX9031芯片，单颗算力1000TOPS，双芯片总算力2000TOPS；第一代产品曾搭载Mobileye EyeQ4芯片，算力2.5TOPS；\\n自研芯片：自研5nm制程神玑NX9031智驾芯片2025年4月量产首搭ET9，性能等效4颗Orin-X；自研激光雷达主控芯片「杨戬」点云处理算力达8百万点/秒，优化30%处理延迟，降低50%功耗。","raw_value":"车端芯片：NT2.0平台车型搭载4颗英伟达Orin X芯片，智驾总算力1016TOPS；ET9搭载双自研神玑NX9031芯片，单颗算力1000TOPS，双芯片总算力2000TOPS；第一代产品曾搭载Mobileye EyeQ4芯片，算力2.5TOPS；\\n自研芯片：自研5nm制程神玑NX9031智驾芯片2025年4月量产首搭ET9，性能等效4颗Orin-X；自研激光雷达主控芯片「杨戬」点云处理算力达8百万点/秒，优化30%处理延迟，降低50%功耗。","unit":null,"data_source":"Agent final_report","source_link":"https://www.thepaper.cn/newsDetail_forward_28053830","quote_text":"【算法路线证据】对于蔚来来说，在端到端大模型方面采用的是渐进式的路线。在他们看来做端到端大模型的前提是要让智驾各功能模块都已形成模型化，具备足够的性能和工程效率。简单说就像是先有每块功能化的拼图，然后组装为整张端到端的完整拼图，不然就像蔚来智能驾驶研发副总裁任少卿认为的那样“否则端到端就是个毒药。”这两天，蔚来推送了Banyan 2.6.5版本，其中包括端到端的AEB功能，可以让AEB避险能力显著增强。随着今年6月蔚来内部智驾团队架构完成调整后，蔚来也成为了率先量产端到端智驾功能的车企。\\n【算力基础设施证据】算力竞赛升级（1000＋TOPS）：芯片单颗算力普遍瞄准400 TOPS以上，蔚来神机NX9031和小鹏图灵更是突破700-1000＋TOPS，满足更高阶自动驾驶（L3＋）的算力需求。先进制程成为主流（7nm／5nm）：主要芯片均采用7nm（华为、小鹏、芯擎）或更先进的5nm（蔚来）制程工艺，紧跟技术前沿。首搭车型定位清晰：芯片将率先搭载在各自品牌的旗舰或高端车型上（如蔚来ET9、小鹏G7 Ultra），覆盖22-80万价格区间。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_5209493","collection_result_row_id":"CRR_ALGO_COMPUTE_5209493_COMPUTEPOWERDESC","collected_at":"2026-03-13 15:13:04"}}'),
