UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"模块化方案：核心感知决策算法由上汽人工智能实验室、零束自研，同时整合地平线、鸿蒙智行（华为）、卓驭（原大疆车载）、Momenta四大供应商方案，覆盖不同品牌车型需求\\n前沿演进：自研一段式端到端直觉式智驾大模型、多模态大模型（VLM/VLA）算法、BEV+Transformer+Occupancy网络技术，已实现量产上车\\n多路线并存：采用「单车智能+车路协同」双线并行，L2+级量产用BEV感知+占用网络方案，L4级高阶用多模大模型决策+冗余安全机制路径","raw_value":"模块化方案：核心感知决策算法由上汽人工智能实验室、零束自研，同时整合地平线、鸿蒙智行（华为）、卓驭（原大疆车载）、Momenta四大供应商方案，覆盖不同品牌车型需求\\n前沿演进：自研一段式端到端直觉式智驾大模型、多模态大模型（VLM/VLA）算法、BEV+Transformer+Occupancy网络技术，已实现量产上车\\n多路线并存：采用「单车智能+车路协同」双线并行，L2+级量产用BEV感知+占用网络方案，L4级高阶用多模大模型决策+冗余安全机制路径","unit":null,"data_source":"Agent final_report","source_link":"https://hao.m.yiche.com/wenzhang/105445653/","quote_text":"1.算法路线相关证据：上汽自研端到端感知、在线建图、AI横纵向耦合算法；BEV算法；一段式端到端直觉式智驾大模型；多模态大模型（VLM/VLA）算法；零束自研智驾平台搭载高实时软件计算平台、BEV算法、全域闭环数据工场，提供端到端融合智驾功能；与Momenta联合开发D.L.P.人工智能模型、Transformer架构决策规划算法、基于Occupancy网络模型的DDOD/DDLD算法；与地平线、鸿蒙智行（华为）、卓驭（原大疆车载）、Momenta四大供应商合作，整合各方智驾算法方案。2023年以来实施「单车智能+车路协同」双线并行技术路径，L2+级量产算法采用「BEV感知+Transformer占用网络」技术方案，已落地飞凡、荣威、名爵多款量产车型；L4级高阶算法采用「多模大模型决策+冗余安全机制」路径，优先在Robotaxi、干线物流场景试点落地。\\n2.算力基础设施相关证据：地平线征程6车载智能计算方案算力达560TOPS，为荣威、MG品牌提供10-560TOPS的算力支持；主流搭载英伟达OrinX芯片（算力500TOPS+）；享道Robotaxi拥有600TOPS强大算力；自有智能驾驶算力集群峰值算力1.2EFLOPS（FP16精度下），配套超100PB存储，联合阿里云搭建国内车企规模领先的智驾训练算力平台，支持PB级智驾数据并行处理、百万级车载终端数据实时接入，可将智能驾驶模型训练效率提升3倍以上，为旗下智己、飞凡、荣威、名爵等品牌的高阶智驾方案研发、模型训练、仿真测试全业务流程提供算力支撑。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_285755","collection_result_row_id":"CRR_ALGO_COMPUTE_285755_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：主流搭载英伟达OrinX（500+TOPS）、地平线征程6（10-560TOPS）芯片，享道Robotaxi算力达600TOPS，支持全场景NOA等高阶智驾功能\\n自研算力配套：自有智驾算力集群峰值算力1.2EFLOPS（FP16精度），配套超100PB存储，联合阿里云搭建训练平台，支撑全集团智驾研发全流程","raw_value":"车端芯片：主流搭载英伟达OrinX（500+TOPS）、地平线征程6（10-560TOPS）芯片，享道Robotaxi算力达600TOPS，支持全场景NOA等高阶智驾功能\\n自研算力配套：自有智驾算力集群峰值算力1.2EFLOPS（FP16精度），配套超100PB存储，联合阿里云搭建训练平台，支撑全集团智驾研发全流程","unit":null,"data_source":"Agent