INSERT INTO collection_results (id, fetch_task_id, schedule_job_id, external_task_id, task_group_id, batch_id, wide_table_id, row_id, raw_result_json, final_report, normalized_rows_json, status, error_msg, duration_ms, collected_at) VALUES
('CR_ALGO_COMPUTE_286316', 'FT_ALGO_COMPUTE_286316', 'SCHED_ALGO_COMPUTE_286316', 'b26571e0-f9a4-4195-b941-b38813460b9d', @task_group_id, @batch_id, @wide_table_id, 29, '{"task_id":"b26571e0-f9a4-4195-b941-b38813460b9d","subject":{"comcode":"286316","company_name":"长安汽车"},"success":true,"status":"completed","final_report":"### 表名: 智能驾驶企业技术布局表\\n| comcode | 企业名称 | algodesc (算法路线，汇总为单个单元格，\\\\n分隔维度) | computepowerdesc (算力基础设施，汇总为单个单元格，\\\\n分隔维度) | Min_Value | Max_Value | Source_URL | Source_Evidence |\\n| ------- | -------- | ------------------------------------------------ | ------------------------------------------------------------ | --------- | --------- | ---------- | --------------- |\\n| 286316 | 长安汽车 | 模块化方案：采用自研+供应商双轨模式，高阶算法自主研发，中低阶采用成熟供应商方案降本，覆盖全场景智驾需求<br>前沿演进：自研天枢智驾系统搭载端到端大模型，2025年首发AIEV交互式智驾，规划2026年落地全场景L3、2028年突破L4<br>多路线并存：感知采用激光雷达与纯视觉并行，旗下品牌差异化布局：启源纯自研、深蓝自研+合作、阿维塔搭载华为智驾 | 车端芯片：深蓝车型搭载地平线J6E（200TOPS），阿维塔搭载华为MDC610（200TOPS），SDA架构域控制器最高支持超1000TOPS拓展算力<br>自研芯片：规划自研智驾芯片算力达508TOPS，暂无公开量产落地信息 | - | - | [链接1](https://htfic.htzq.com.cn/ht/report/vsat/2025/06/18/202506180002GC003W.pdf)<br>[链接2](https://htfic.htzq.com.cn/ht/report/vsat/2025/06/10/202506100002HC004H.pdf)<br>[链接3](http://m.toutiao.com/group/7470420731382202920/?upstream_biz=VolcEngine)<br>[链接4](https://m.36kr.com/p/3162072837270018)<br>[链接5](https://www.dongchedi.com/article/7550268049279042099)<br>[链接6](https://www.dongchedi.com/article/7584291137641415230)<br>[链接7](https://itstech.blog.csdn.net/article/details/158637967) | 【算法路线来源证据1】长安汽车坚持“自主研发＋合作共创”，与华为在智能驾驶领域深度合作，智驾技术方案为多种方案并行，感知路线采用激光雷达与纯视觉并行，大算力芯片采用供应商方案，算法为自研+供应商结合。<br>【算法路线来源证据2】长安汽车采用“深度自研+开放合作”的中间路线，“北斗天枢2.0”战略下自研天枢智驾系统，合作端与华为等深化合作，推动乾崑智驾在阿维塔、深蓝产品上应用，自研智驾采用端到端技术、天枢大模型支撑，2025年首发AIEV端到端交互式智驾，旗下品牌按智驾来源区分：长安启源为纯血自研智驾，深蓝为自研与合作综合体，阿维塔为与华为合作的高端智驾品牌，自研团队已超过1700人。<br>【算法路线来源证据3】长安汽车采用全栈自研+开放生态双轨模式，高阶智能驾驶核心算法优先自研，中低阶智能驾驶场景搭配供应商成熟方案降本，覆盖高速、城区、泊车全场景需求，自研北斗天枢体系高阶智能驾驶算法已实现全场景覆盖，2024年已搭载于三大新能源品牌多款量产车型。<br>【算力基础设施来源证据1】长安深蓝车型搭载地平线J6E芯片，算力约200TOPS；长安阿维塔车型搭载华为MDC610+ADS方案，算力约200TOPS。<br>【算力基础设施来源证据2】长安汽车SDA天枢架构先进，最高算力超1000Tops，2024-2025年相关搭载车型上市；自研智驾芯片算力为508TOPS。 |","table_data":[],"error":"","duration":180.324}', '### 表名: 智能驾驶企业技术布局表
