INSERT INTO collection_result_rows (id, collection_result_id, fetch_task_id, schedule_job_id, wide_table_id, row_id, indicator_key, indicator_name, business_date, dimension_values_json, raw_value, cleaned_value, unit, published_at, source_site, source_url, quote_text, max_value, min_value, confidence, status, warning_msg, reasoning, why_not_found) VALUES
