UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"模块化方案：采用多传感器冗余+混合决策架构，感知层融合激光雷达+视觉，决策层融合规则+强化学习，全流程覆盖感知、决策、规划与控制，落地L2+到L4多级别智驾产品，支持高速、城市、泊车全场景覆盖\\n前沿演进：迭代4D BEV Transformer感知模型，采用端到端大模型+传统规则链双备份规控架构，依托文心大底座搭建自动驾驶专属训练框架，落地行业首个地图生成大模型，制图成本降低95%\\n多路线并存：探索L4技术与L2+技术共生、纯视觉+激光雷达感知冗余、单车智能+车路协同(Apollo Air)多路线并行，支持不同场景、不同成本的智驾需求","raw_value":"模块化方案：采用多传感器冗余+混合决策架构，感知层融合激光雷达+视觉，决策层融合规则+强化学习，全流程覆盖感知、决策、规划与控制，落地L2+到L4多级别智驾产品，支持高速、城市、泊车全场景覆盖\\n前沿演进：迭代4D BEV Transformer感知模型，采用端到端大模型+传统规则链双备份规控架构，依托文心大底座搭建自动驾驶专属训练框架，落地行业首个地图生成大模型，制图成本降低95%\\n多路线并存：探索L4技术与L2+技术共生、纯视觉+激光雷达感知冗余、单车智能+车路协同(Apollo Air)多路线并行，支持不同场景、不同成本的智驾需求","unit":null,"data_source":"Agent final_report","source_link":"https://htfic.htzq.com.cn/ht/report/vsat/2025/06/04/202506040002HC00A1.pdf","quote_text":"【算法路线相关证据】1. 百度的自动驾驶系统（Apollo）融合了多类核心算法，涵盖感知、决策、规划与控制全流程。环境感知采用深度学习视觉模型（CNN、BEV Transformer）、激光雷达点云处理（PointPillars）、多传感器融合（卡尔曼滤波+深度学习）；决策规划采用行为决策（MDP/POMDP、模仿学习）、路径规划（A*优化算法、Frenet坐标系）；运动控制采用模型预测控制（MPC）、PID+强化学习；特色技术包含车路协同（V2X）多智能体强化学习、高精地图匹配（SLAM+语义分割），采用多传感器冗余+混合决策架构，适合中国复杂路况。2. 百度探索L4技术与L2+城市智驾技术共生，将自动驾驶技术落地高级辅助驾驶产品ANP3.0，L4将持续为L2+智驾产品提供先进技术迁移与海量数据积累，L2数据的反哺也将助力L4泛化能力提升。3. ANP3 Pro采用纯视觉技术路线，搭载1颗NVIDIA DRIVE Orin(254TOPS)，可覆盖泊车、高速、城市等全域出行场景，同时探索端到端大模型技术应用于旗舰智驾产品ANP3 MAX。4. Apollo高精地图融合实时地图构建及定位技术、深度学习、图像处理、计算几何等多种先进处理技术，建立亿量级样本库；落地行业首个地图生成大模型，实现端到端车道网络新范式，地图制图成本降低95%。5. Apollo Air是全球唯一仅通过路侧感知就能实现开放道路L4自动驾驶闭环的技术，可在车端无传感器、仅借助路端轻量感知和红绿灯信息的情况下，通过V2X、5G等无线通信技术实现车-路-云的信息交互赋能自动驾驶，车路协同可解决单车智能路测时54%左右的问题，减少62%的接管次数，降低30%的单车成本。6. 2024年公开的技术路线采用多模态大模型+车端多传感器融合架构，BEV感知模型已迭代至4D版本，规控采用端到端大模型+传统规则链双备份架构，端到端规控大模型可处理超10万种城市复杂场景，依托百度文心大模型底座，搭建自动驾驶专属大模型训练框架，训练数据规模超1亿公里真实驾驶数据。\\n【算力基础设施相关证据】1. 百度Apollo发布“芯片X计划”，只要芯片算力满足100TOPS（稠密算力），即可体验ANP3 Pro领先的高阶智驾能力，ANP3 Pro搭载1颗NVIDIA DRIVE Orin（254TOPS），搭载2颗NVIDIA DRIVE Orin（508TOPS）的Apollo ANP3 MAX可支持25万元以上的新能源车型。2. 百度Apollo推出旗舰产品城市智驾Apollo City Driving Max，搭载两颗英伟达Orin X，算力达508TOPS，是国内唯一一款使用纯视觉感知就能在城市道路上带给用户连贯体验的产品。3. 行泊一体产品Apollo Highway Driving Pro算力平台升级至单TDA4-VH平台，能在更低算力、更低成本条件下实现更高阶的行泊一体功能。4. 纯视觉方案的实现背靠百度云海量的AI算力集群实现周级模型迭代，为智驾持续进化保驾护航。5. 算力上，百度百舸AI计算平台5.0内置自动驾驶模型专项加速能力，训练效率大幅提升；算力层，百度自研昆仑芯点亮国内首个全自研3万卡集群，可承载多个千亿参数大模型全量训练，新一代昆仑芯M100、M300针对不同任务优化，配合天池超节点，单个天池512超节点可支撑万亿参数模型训练。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_1158390","collection_result_row_id":"CRR_ALGO_COMPUTE_1158390_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：主流方案适配NVIDIA DRIVE Orin芯片，Pro版单颗254TOPS，MAX版双颗508TOPS，行泊一体方案适配单TDA4-VH平台，最低支持100TOPS稠密算力芯片搭载\\n自研芯片：底层采用GPU+自研昆仑芯异构架构，点亮国内首个全自研3万卡昆仑芯集群，配套百舸AI计算平台5.0专项加速智驾模型训练，训练效率显著提升","raw_value":"车端芯片：主流方案适配NVIDIA DRIVE Orin芯片，Pro版单颗254TOPS，MAX版双颗508TOPS，行泊一体方案适配单TDA4-VH平台，最低支持100TOPS稠密算力芯片搭载\\n自研芯片：底层采用GPU+自研昆仑芯异构架构，点亮国内首个全自研3万卡昆仑芯集群，配套百舸AI计算平台5.0专项加速智驾模型训练，训练效率显著提升","unit":null,"data_source":"Agent final_report","source_link":"https://htfic.htzq.com.cn/ht/report/vsat/2025/06/04/202506040002HC00A1.pdf","quote_text":"【算法路线相关证据】1. 百度的自动驾驶系统（Apollo）融合了多类核心算法，涵盖感知、决策、规划与控制全流程。环境感知采用深度学习视觉模型（CNN、BEV Transformer）、激光雷达点云处理（PointPillars）、多传感器融合（卡尔曼滤波+深度学习）；决策规划采用行为决策（MDP/POMDP、模仿学习）、路径规划（A*优化算法、Frenet坐标系）；运动控制采用模型预测控制（MPC）、PID+强化学习；特色技术包含车路协同（V2X）多智能体强化学习、高精地图匹配（SLAM+语义分割），采用多传感器冗余+混合决策架构，适合中国复杂路况。2. 百度探索L4技术与L2+城市智驾技术共生，将自动驾驶技术落地高级辅助驾驶产品ANP3.0，L4将持续为L2+智驾产品提供先进技术迁移与海量数据积累，L2数据的反哺也将助力L4泛化能力提升。3. ANP3 Pro采用纯视觉技术路线，搭载1颗NVIDIA DRIVE Orin(254TOPS)，可覆盖泊车、高速、城市等全域出行场景，同时探索端到端大模型技术应用于旗舰智驾产品ANP3 MAX。4. Apollo高精地图融合实时地图构建及定位技术、深度学习、图像处理、计算几何等多种先进处理技术，建立亿量级样本库；落地行业首个地图生成大模型，实现端到端车道网络新范式，地图制图成本降低95%。5. Apollo Air是全球唯一仅通过路侧感知就能实现开放道路L4自动驾驶闭环的技术，可在车端无传感器、仅借助路端轻量感知和红绿灯信息的情况下，通过V2X、5G等无线通信技术实现车-路-云的信息交互赋能自动驾驶，车路协同可解决单车智能路测时54%左右的问题，减少62%的接管次数，降低30%的单车成本。6. 2024年公开的技术路线采用多模态大模型+车端多传感器融合架构，BEV感知模型已迭代至4D版本，规控采用端到端大模型+传统规则链双备份架构，端到端规控大模型可处理超10万种城市复杂场景，依托百度文心大模型底座，搭建自动驾驶专属大模型训练框架，训练数据规模超1亿公里真实驾驶数据。\\n【算力基础设施相关证据】1. 百度Apollo发布“芯片X计划”，只要芯片算力满足100TOPS（稠密算力），即可体验ANP3 Pro领先的高阶智驾能力，ANP3 Pro搭载1颗NVIDIA DRIVE