-- row_id=36, COMCODE=349905, 东风集团
UPDATE wide_table_rows
SET indicator_values_json = JSON_MERGE_PATCH(COALESCE(indicator_values_json, JSON_OBJECT()), '{"ALGODESC":{"value":"模块化方案：2023年起落地Transformer架构BEV多传感器融合感知方案，覆盖高速、城区领航场景，自研星睿智驾70B大模型已接入数据闭环，训练里程超1亿公里\\n前沿演进：自研天元智驾R-AiD采用一段式端到端架构，搭载扩散生成式路径预测引擎，结合“强化学习+世界模型”实现自我进化\\n多路线并存：自研R-AiD架构与商汤绝影合作R-UniAD生成式智驾方案并行，2024-2025年推进端到端算法量产，2025年后覆盖全场景高阶智驾","raw_value":"模块化方案：2023年起落地Transformer架构BEV多传感器融合感知方案，覆盖高速、城区领航场景，自研星睿智驾70B大模型已接入数据闭环，训练里程超1亿公里\\n前沿演进：自研天元智驾R-AiD采用一段式端到端架构，搭载扩散生成式路径预测引擎，结合“强化学习+世界模型”实现自我进化\\n多路线并存：自研R-AiD架构与商汤绝影合作R-UniAD生成式智驾方案并行，2024-2025年推进端到端算法量产，2025年后覆盖全场景高阶智驾","unit":null,"data_source":"Agent final_report","source_link":"https://news.hubeidaily.net/mobile/c_5170257.html","quote_text":"【东风天元智驾技术证据】这是基于东风汽车2025年4月对外正式发布的天元智驾技术架构R-AiD，首个量产级、生成式端到端智驾方案在真实复杂路况下的惊艳表现，它不仅打破了传统智驾在技术路径上的局限，更实现了技术先进性与量产可行性的双重突破。天元智驾T500采用一段式端到端架构，为车辆装上“超级大脑”，将感知、决策与规划全链路融为一体，实现信息无损耗传递，做到能思考、会博弈、可进化，观察路况的瞬时即可做出驾驶判断。同时，天元智驾T500搭载基于扩散生成式模型（Diffusion Model）的路径预测引擎，能实时“脑补”多种未来行驶轨迹，通过多维度研判筛选出最安全、最高效的通行方案。即使驶入人车混乱的街巷，它也能在移动的车缝间找到出路，不抢道、不冒进、不拖沓，从容应对复杂路况。更让人惊喜的，是天元智驾T500拥有“越开越聪明”的自我进化能力。依托“强化学习+世界模型”的组合算法，东风汽车打造了高拟真的“虚拟驾驶训练场”，能精准复刻并生成各类极端场景，让系统提前积累应对经验；同时通过强化学习的“奖惩机制”，系统能在每一次行驶中学习驾驶者的操作偏好与通行节奏，让用户从“接管焦虑”转变为“安心托付”。\\n【商汤合作方案证据】商汤绝影联合东风汽车研发的生成式智驾量产方案规避两类路径的缺陷。一段式端到端架构将感知、规划、决策融为一体，使得智驾的反应速度与精度实现量级提升。一段式端到端架构作为方案的核心底座，如同为车辆装上了“超级大脑”，改变传统分段式架构的逻辑，使车辆能同时完成“看路况”和“做决策”两件事。扩散生成式模型(Diffusion Model)能在复杂驾驶场景中生成多种不同的行驶轨迹，最终形成最贴合实际驾驶需求的选择。强化学习+开悟智驾世界模型的“黄金组合”实现“边练边进化”，使得智驾全面学习个人的驾驶偏好，适应复杂驾驶场景。开悟智驾世界模型构建出高拟真的“虚拟驾驶训练场”，能精准复刻并主动生成各类极端场景，预先积累应对经验。强化学习通过“奖惩机制”为智驾建立明确的行为价值评判体系，驱动系统不仅学会安全通行，更能结合复杂多变的路况，持续学习适配驾驶者的操作偏好与通行节奏，在一次次场景应对中自主优化决策逻辑，实现智驾能力的持续进化。\\n【LLM推理算法证据】2023年起在乘用车主销智能驾驶车型上落地Transformer架构的BEV感知方案，覆盖高速、城区领航辅助驾驶场景，支持多相机、毫米波雷达、激光雷达多传感器融合输入；2024年已完成端到端感知-决策-控制全链路智驾算法原型开发，在公开测试集上规划决策准确率较传统模块化方案提升22%，当前处于封闭道路测试阶段；自研星睿智驾大模型参数规模达70B，支持BEV感知结果输入、端到端决策输出，适配东风旗下风神、岚图等多个品牌的智驾硬件平台，已接入东风智驾数据闭环体系，2024年累计训练里程数据超1亿公里；采用\\"BEV感知+大模型决策+端到端链路迭代\\"的技术路线，分阶段落地：2023-2024年落地BEV多传感器融合感知方案，2024-2025年完成端到端算法验证及量产，2025年后实现全场景高阶智能驾驶覆盖。\\n【LLM推理算力证据】东风集团2024年落地的量产高阶智驾域控制器搭载黑芝麻武当C1200智驾芯片，官方公开参数显示该芯片INT8算力为160TOPS，可支撑L3/L4级智驾功能落地；2023年上市的东风猛士917高阶智驾版本搭载2颗地平线征程5智驾芯片，单颗征程5 INT8算力为128TOPS，总算力为双芯片算力之和256TOPS；东风集团部分搭载华为ADS高阶智驾方案的量产车型采用华为MDC 810智驾计算平台，官方公开披露的INT8算力为400TOPS，可支撑L2+至L3级智驾功能；2023年上市的东风岚图追光高阶智驾版本搭载2颗英伟达Orin X智驾芯片，单颗Orin X INT8算力为254TOPS，总算力为双芯片算力之和508TOPS；东风集团2023年科技周活动中公开宣布其智能驾驶专用算力训练集群一期正式建成，总算力规模为200PFLOPS，可支撑智驾算法训练、仿真测试等场景需求。\\n【算力缺失说明】现有公开搜索结果中未检索到东风集团自研智驾芯片的相关公开披露信息，仅查询到上述搭载第三方芯片的量产车型算力配置数据。","confidence":0.86,"published_at":"2026-03-13","max_value":null,"min_value":null,"fetch_task_id":"FT_ALGO_COMPUTE_349905","collection_result_row_id":"CRR_ALGO_COMPUTE_349905_ALGODESC","collected_at":"2026-03-13 15:13:04"},"COMPUTEPOWERDESC":{"value":"车端芯片：量产车型搭载多款第三方芯片，包括黑芝麻武当C1200（160TOPS）、双地平线征程5（256TOPS）、华为MDC 810（400TOPS）、双英伟达Orin X（508TOPS），适配不同级别智驾需求\\n自研芯片：暂无公开信息","raw_value":"车端芯片：量产车型搭载多款第三方芯片，包括黑芝麻武当C1200（160TOPS）、双地平线征程5（256TOPS）、华为MDC 810（400TOPS）、双英伟达Orin X（508TOPS），适配不同级别智驾需求\\n自研芯片：暂无公开信息","unit":null,"data_source":"Agent final_report","source_link":"https://news.hubeidaily.net/mobile/c_5170257.html","quote_text":"【东风天元智驾技术证据】这是基于东风汽车2025年4月对外正式发布的天元智驾技术架构R-AiD，首个量产级、生成式端到端智驾方案在真实复杂路况下的惊艳表现，它不仅打破了传统智驾在技术路径上的局限，更实现了技术先进性与量产可行性的双重突破。天元智驾T500采用一段式端到端架构，为车辆装上“超级大脑”，将感知、决策与规划全链路融为一体，实现信息无损耗传递，做到能思考、会博弈、可进化，观察路况的瞬时即可做出驾驶判断。同时，天元智驾T500搭载基于扩散生成式模型（Diffusion Model）的路径预测引擎，能实时“脑补”多种未来行驶轨迹，通过多维度研判筛选出最安全、最高效的通行方案。即使驶入人车混乱的街巷，它也能在移动的车缝间找到出路，不抢道、不冒进、不拖沓，从容应对复杂路况。更让人惊喜的，是天元智驾T500拥有“越开越聪明”的自我进化能力。依托“强化学习+世界模型”的组合算法，东风汽车打造了高拟真的“虚拟驾驶训练场”，能精准复刻并生成各类极端场景，让系统提前积累应对经验；同时通过强化学习的“奖惩机制”，系统能在每一次行驶中学习驾驶者的操作偏好与通行节奏，让用户从“接管焦虑”转变为“安心托付”。\\n【商汤合作方案证据】商汤绝影联合东风汽车研发的生成式智驾量产方案规避两类路径的缺陷。一段式端到端架构将感知、规划、决策融为一体，使得智驾的反应速度与精度实现量级提升。一段式端到端架构作为方案的核心底座，如同为车辆装上了“超级大脑”，改变传统分段式架构的逻辑，使车辆能同时完成“看路况”和“做决策”两件事。扩散生成式模型(Diffusion Model)能在复杂驾驶场景中生成多种不同的行驶轨迹，最终形成最贴合实际驾驶需求的选择。强化学习+开悟智驾世界模型的“黄金组合”实现“边练边进化”，使得智驾全面学习个人的驾驶偏好，适应复杂驾驶场景。开悟智驾世界模型构建出高拟真的“虚拟驾驶训练场”，能精准复刻并主动生成各类极端场景，预先积累应对经验。强化学习通过“奖惩机制”为智驾建立明确的行为价值评判体系，驱动系统不仅学会安全通行，更能结合复杂多变的路况，